{
    "level": "A1–B1",
    "intro": "In this topic you will learn <strong>special questions (Wh-questions)</strong> - questions that begin with question words and require specific information in the answer.",
    "rules": [
        {
            "label": "WHO / WHAT",
            "color": "emerald",
            "text": "<strong>Who? What?</strong> - questions about people and things:",
            "example": "Who is she? What do you want?"
        },
        {
            "label": "WHERE / WHEN",
            "color": "blue",
            "text": "<strong>Where? When?</strong> - questions about place and time:",
            "example": "Where do you live? When does it start?"
        },
        {
            "label": "WHY / HOW",
            "color": "amber",
            "text": "<strong>Why? How?</strong> - a question about the reason and method:",
            "example": "Why are you late? How does it work?"
        }
    ]
}

{
    "title": "1. What are Wh-questions?",
    "intro": "Wh-questions (special questions) are questions with question words that require a detailed answer:",
    "items": [
        {
            "label": "General question",
            "title": "Do you like coffee?",
            "subtitle": "Answer: Yes/No"
        },
        {
            "label": "Special Question",
            "title": "What do you like? WHO — Who? (about people)",
            "subtitle": "Відповідь: I like tea."
        },
        {
            "label": "Структура",
            "title": "Wh-word + Auxiliary + Subject + Verb",
            "subtitle": "Питальне слово завжди на початку"
        }
    ]
}

{
    "title": "2. WHO — Хто? (про людей)",
    "sections": [
        {
            "label": "WHO - a question about a person",
            "color": "emerald",
            "description": "<strong>Who</strong> (who) - used when asking about a person as an adjunct.",
            "examples": [
                {
                    "en": "Who do you love?",
                    "ua": "Who do you love?"
                },
                {
                    "en": "Who did you see?",
                    "ua": "Who did you see?"
                },
                {
                    "en": "Who are you talking to?",
                    "ua": "Who do you talk to?"
                },
                {
                    "en": "Who does she work with?",
                    "ua": " who does she work for?"
                }
            ]
        },
        {
            "label": "WHO is a question to the subject",
            "color": "sky",
            "description": "When <strong>who</strong> is the subject, do NOT use the auxiliary verb do/does/did.",
            "examples": [
                {
                    "en": "Who lives here?",
                    "ua": "Who lives here?"
                },
                {
                    "en": "Who called you?",
                    "ua": "Who called you?"
                },
                {
                    "en": "Who wants coffee?",
                    "ua": "Who wants coffee?"
                },
                {
                    "en": "Who knows the answer?",
                    "ua": "Who knows the answer?"
                }
            ]
        },
        {
            "label": "WHO — with various sometimes",
            "color": "purple",
            "description": "Who can be used with different tenses.",
            "examples": [
                {
                    "en": "Who is coming to the party?",
                    "ua": "Who has finished the work?"
                },
                {
                    "en": "Who has finished the work?",
                    "ua": "Who has finished the work?"
                },
                {
                    "en": "Who will help me?",
                    "ua": "Who will help me?"
                }
            ],
            "note": "📌 Structure: Who + Auxiliary + Subject + Verb? (or Who + Verb? for questions about the subject)"
        }
    ]
}

{
    "title": "3. WHAT — What? (about things and information)",
    "sections": [
        {
            "label": "WHAT - general questions",
            "color": "blue",
            "description": "<strong>What</strong> (what) - used to ask about things, actions or information.",
            "examples": [
                {
                    "en": "What do you want?",
                    "ua": "What do you want?"
                },
                {
                    "en": "What did she say?",
                    "ua": "What did she say?"
                },
                {
                    "en": "What are you doing?",
                    "ua": "What are you doing?"
                },
                {
                    "en": "What is your name?",
                    "ua": "What is your name? (What is your name?)"
                }
            ]
        },
        {
            "label": "WHAT + noun",
            "color": "amber",
            "description": "<strong>What</strong> can be used together with a noun for clarification.",
            "examples": [
                {
                    "en": "What color is it?",
                    "ua": "What color is it?"
                },
                {
                    "en": "What time is it?",
                    "ua": "What time?"
                },
                {
                    "en": "What kind of music do you like?",
                    "ua": "What size do you need?"
                },
                {
                    "en": "What size do you need?",
                    "ua": "What size do you need?"
                }
            ]
        },
        {
            "label": "WHAT is a question for subject",
            "color": "rose",
            "description": "When <strong>what</strong> is the subject, we don't use do/does/did.",
            "examples": [
                {
                    "en": "What happened?",
                    "ua": "What happened?"
                },
                {
                    "en": "What makes you happy?",
                    "ua": " happy?"
                },
                {
                    "en": "What caused the problem?",
                    "ua": "What happened?"
                }
            ],
            "note": "📌 What happened? — NOT What did happen?"
        }
    ]
}

{
    "title": "4. WHERE — Where? (about a place)",
    "sections": [
        {
            "label": "WHERE - a question about a place",
            "color": "emerald",
            "description": "<strong>Where</strong> (where, where) - used to ask a question about a place or direction.",
            "examples": [
                {
                    "en": "Where do you live?",
                    "ua": "Where do you live?"
                },
                {
                    "en": "Where are you going?",
                    "ua": "Where are you going?"
                },
                {
                    "en": "Where did you buy it?",
                    "ua": "Where is the bank?"
                },
                {
                    "en": "Where is the bank?",
                    "ua": "Where is the bank?"
                }
            ]
        },
        {
            "label": "WHERE prepositions",
            "color": "sky",
            "description": "Where can be used with prepositions <strong>from, to, at</strong>, etc.",
            "examples": [
                {
                    "en": "Where are you from?",
                    "ua": "Where are you from?"
                },
                {
                    "en": " Where are you going to? WHEN — When? about time) happen?",
                    "ua": "Куди ти збираєшся?"
                },
                {
                    "en": "Where did she come from?",
                    "ua": "Звідки вона прийшла?"
                }
            ],
            "note": "📌 Структура: Where + Auxiliary + Subject + Verb?"
        }
    ]
}

{
    "title": "5. WHEN — Коли? (про час)",
    "sections": [
        {
            "label": "WHEN — питання про час",
            "color": "blue",
            "description": "<strong>When</strong> (коли) — використовуємо для запитання про час події.",
            "examples": [
                {
                    "en": "When do you wake up?",
                    "ua": "Коли ти прокидаєшся?"
                },
                {
                    "en": "When did it happen?",
                    "ua": "When will you come back?"
                },
                {
                    "en": "When are you leaving?",
                    "ua": "When will you come back?"
                },
                {
                    "en": "When will you come back?",
                    "ua": "When are you leaving?"
                }
            ]
        },
        {
            "label": "WHEN - different tenses forms",
            "color": "purple",
            "description": "When works with all tenses.",
            "examples": [
                {
                    "en": "When is your birthday?",
                    "ua": "When does the meeting start?"
                },
                {
                    "en": "When does the meeting start?",
                    "ua": "When does the meeting start?"
                },
                {
                    "en": "When have you been there?",
                    "ua": "When were you there?"
                }
            ],
            "note": "📌 The answer can be specific (at 5 pm) or general (tomorrow, yesterday)"
        }
    ]
}

{
    "title": "6. WHY — Why? (about the reason)",
    "sections": [
        {
            "label": "WHY - a question about the reason",
            "color": "amber",
            "description": "<strong>Why</strong> (why) - used to ask about the reason or purpose.",
            "examples": [
                {
                    "en": "Why are you sad?",
                    "ua": "Why are you sad?"
                },
                {
                    "en": "Why did she leave?",
                    "ua": "Why did she leave?"
                },
                {
                    "en": "Why do you study English?",
                    "ua": "Why do you study English?"
                },
                {
                    "en": "Why is this important?",
                    "ua": "Why is it important?"
                }
            ]
        },
        {
            "label": "WHY is the answer with BECAUSE",
            "color": "rose",
            "description": "The question <strong>why</strong> is usually answered with <strong>because</strong> (because).",
            "examples": [
                {
                    "en": "Why are you late? — Because I missed the bus.",
                    "ua": "Why were you late? — Because I missed the bus."
                },
                {
                    "en": "Why is she angry? — Because he forgot her birthday.",
                    "ua": "Why is she angry? — Because he forgot her birthday."
                }
            ]
        },
        {
            "label": "WHY - suggestions and advice",
            "color": "emerald",
            "description": "Why can be used for suggestions or advice in the construction <strong>Why don't we/you...?</strong>",
            "examples": [
                {
                    "en": "Why don't we go to the cinema?",
                    "ua": "Why don't we go to the cinema? movie?"
                },
                {
                    "en": "Why don't you ask him?",
                    "ua": "Why don't you ask him?"
                }
            ],
            "note": "📌 Why don't we/you...? = suggestion or advice"
        },
        {
            "label": "WHY with modal verbs",
            "color": "purple",
            "description": "Why can be used with modal verbs <strong>(should, can, could, would, must)</strong> to ask about the reason for an obligation, possibility or condition.",
            "examples": [
                {
                    "en": "Why should I believe you?",
                    "ua": "Why should I should I believe you?"
                },
                {
                    "en": "Why would she do that?",
                    "ua": "Why can't we stay longer?"
                },
                {
                    "en": "Why can't we stay longer?",
                    "ua": "Why can't we stay longer?"
                },
                {
                    "en": "Why must you leave now?",
                    "ua": "Why do you have to go now?"
                }
            ],
            "note": "📌 Structure: Why + Modal Verb + Subject + Main Verb?"
        }
    ]
}

{
    "title": "7. HOW? (about method and degree)",
    "sections": [
        {
            "label": "HOW is a question about method",
            "color": "blue",
            "description": "<strong>How</strong> (як) — використовуємо для запитання про спосіб, метод або стан.",
            "examples": [
                {
                    "en": "How do you go to work?",
                    "ua": "Як ти їдеш на роботу?"
                },
                {
                    "en": "How does it work?",
                    "ua": "Як це працює?"
                },
                {
                    "en": "How are you?",
                    "ua": "How are you? How are you?) you?"
                },
                {
                    "en": "How did you learn English?",
                    "ua": "Як ти вивчив англійську?"
                }
            ]
        },
        {
            "label": "HOW + прикметник/прислівник",
            "color": "purple",
            "description": "<strong>How</strong> комбінується з прикметниками для запитання про ступінь, кількість, відстань.",
            "examples": [
                {
                    "en": "How old are you?",
                    "ua": " How old are you? take?"
                },
                {
                    "en": "How tall is he?",
                    "ua": "Якого він зросту?"
                },
                {
                    "en": "How far is the station?",
                    "ua": "Як далеко станція?"
                },
                {
                    "en": "How long does it take?",
                    "ua": "How long does it take?"
                }
            ]
        },
        {
            "label": "HOW MUCH / HOW MANY",
            "color": "emerald",
            "description": "<strong>How much</strong> (uncountable) / <strong>How many</strong> (countable) - for questions about quantity.",
            "examples": [
                {
                    "en": "How much is it?",
                    "ua": "How much does it cost?"
                },
                {
                    "en": "How many books do you have?",
                    "ua": "How much time do we have?"
                },
                {
                    "en": "How much time do we have?",
                    "ua": "How many people are coming?"
                },
                {
                    "en": "How many people are coming?",
                    "ua": "How many people are coming?"
                }
            ],
            "note": "📌 How much - with uncountable nouns, How many - with countable"
        }
    ]
}

{
    "title": "8. Comparison table of question words",
    "intro": "Main question words and their meanings:",
    "rows": [
        {
            "en": "WHO",
            "ua": "Who? Who?",
            "note": "About people — Who is she? Who did you see?"
        },
        {
            "en": "WHAT",
            "ua": "What? Which one?",
            "note": "About things, information — What do you want? What time?"
        },
        {
            "en": "WHERE",
            "ua": "Where? Where? Where are you from?",
            "note": "About the place — Where do you live? Where from?"
        },
        {
            "en": "WHEN",
            "ua": "When?",
            "note": "About time — When did it happen? When are you coming?"
        },
        {
            "en": "WHY",
            "ua": "Why?",
            "note": "About the reason — Why are you late? → Because..."
        },
        {
            "en": "HOW",
            "ua": "How? How? ",
            "note": "About the method — How do you do it? How old? How much?"
        }
    ],
    "warning": "📌 Structure: <strong>Wh-word + Auxiliary + Subject + Verb + ...?</strong>"
}

{
    "title": "9. Wh-questions structure",
    "sections": [
        {
            "label": "Standard structure",
            "color": "emerald",
            "description": "General formula for most Wh-questions:",
            "examples": [
                {
                    "en": "Wh-word + Auxiliary + Subject + Main Verb + ...?",
                    "ua": "Question word + Auxiliary + Subject + Verb + ...?"
                },
                {
                    "en": "What do you want?",
                    "ua": "What do you want?"
                },
                {
                    "en": "Where did she go? do/does/did:",
                    "ua": "Куди (did) вона (go) пішла?"
                }
            ]
        },
        {
            "label": "Питання до підмета",
            "color": "sky",
            "description": "Коли питальне слово є підметом, НЕ використовуємо do/does/did:",
            "examples": [
                {
                    "en": "Who lives here? (NOT: Who does live here?)",
                    "ua": "Who lives here?"
                },
                {
                    "en": "What happened? (Not: What did happen?)",
                    "ua": "Що сталося?"
                }
            ],
            "note": "📌 Структура: Wh-word (subject) + Verb + ...?"
        },
        {
            "label": "З дієсловом TO BE",
            "color": "amber",
            "description": "З to be робимо інверсію без do/does/did:",
            "examples": [
                {
                    "en": " Where are you? ...?",
                    "ua": "Де ти?"
                },
                {
                    "en": "Who is she?",
                    "ua": "Хто вона?"
                },
                {
                    "en": "What is your name?",
                    "ua": "Як тебе звати?"
                }
            ],
            "note": "📌 Структура: Wh-word + be + Subject + ...?"
        }
    ]
}

{
    "title": "10. Typical errors",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Incorrect word order in the question.",
            "wrong": "❌ What you want? Where you live?",
            "right": " ✅ <span class="font-mono">What do you want? Where do you live?</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Using do/does/did in subject questions.",
            "wrong": "❌ Who does live here? What did happen?",
            "right": "​​​​ <span class="font-mono">Who lives here? What happened?</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Wrong form of the verb after the auxiliary.",
            "wrong": "❌ Where does she lives? What did you see?",
            "right": "​​​​ <span class="font-mono">Where does she live? What did you see?</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "Confusion between How much and How many.",
            "wrong": "❌ How much money? How many people?",
            "right": "​​​​ <span class="font-mono">How much money? How many people?</span>"
        }
    ]
}

{
    "title": "12. Practice",
    "select_title": "Exercise 1. Choose the correct question word",
    "select_intro": "Choose the correct question word for each question.",
    "selects": [
        {
            "label": "_____ is your name? (Who / What / Where)",
            "prompt": "What is the question word?"
        },
        {
            "label": "_____ do you live? (When / Where / Why)",
            "prompt": "What is the question word?"
        },
        {
            "label": "_____ are you learning English? (How / Why / What)",
            "prompt": "What is the question word?"
        },
        {
            "label": "_____ old are you? (What/Where/How) word.",
            "prompt": "Яке питальне слово?"
        }
    ],
    "options": [
        "Перший варіант",
        "Другий варіант",
        "Третій варіант"
    ],
    "input_title": "Вправа 2. Постав питання",
    "input_intro": "Утвори питання, використовуючи подане питальне слово.",
    "inputs": [
        {
            "before": "You live in Kyiv. (Where) → ",
            "after": ""
        },
        {
            "before": "She is 25 years old. (How old) → ",
            "after": ""
        },
        {
            "before": "He went to the park. (Where) → ",
            "after": ""
        },
        {
            "before": "They arrived at 5 pm. (When) → ",
            "after": ""
        }
    ],
    "rephrase_title": "Exercise 3. Correct the error",
    "rephrase_intro": "Find and correct the error in the special question.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "What you want?",
            "example_target": "What do you want?"
        },
        {
            "original": "1. Where she lives?",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. Who does live here?",
            "placeholder": "Fix the error"
        },
        {
            "original": "3. How much money do you have?",
            "placeholder": "Correct the error"
        }
    ]
}

